// S7: Context Compression — สร้าง Context Card 5 fields
const input = $input.first().json;

const contextCard = {
  product_name: input.product_name || '',
  category: input.category || 'otop',
  key_features: input.features || [],
  target_audience: input.audience || 'คนไทยทั่วไป',
  unique_selling_point: input.usp || '',
  hook_preference: input.hook_type || 'auto'
};

// Compress to ~150 chars for efficient context
const compressed = `${contextCard.product_name}|${contextCard.category}|${contextCard.target_audience}|${contextCard.hook_preference}`;

return {
  contextCard,
  compressed,
  timestamp: new Date().toISOString()
};

// S1+S3+S5: Prompt Assembly
// รวม RCCF Prompt + Master Prompt + Category System Prompt

const context = $('S7: Context Card').first().json;
const knowledge = $('S8: Knowledge Base').first().json;

// S5: Category-specific system prompts
const systemPrompts = {
  food: 'คุณเป็นผู้เชี่ยวชาญสร้างคอนเทนต์ TikTok สำหรับอาหารไทย เน้น: รสชาติ, สูตรโบราณ, วัตถุดิบท้องถิ่น',
  craft: 'คุณเป็นผู้เชี่ยวชาญสร้างคอนเทนต์ TikTok สำหรับหัตถกรรม เน้น: ฝีมือช่าง, ภูมิปัญญา, กระบวนการผลิต',
  herb: 'คุณเป็นผู้เชี่ยวชาญสร้างคอนเทนต์ TikTok สำหรับสมุนไพร เน้น: สรรพคุณ, วิธีใช้, ผลลัพธ์',
  textile: 'คุณเป็นผู้เชี่ยวชาญสร้างคอนเทนต์ TikTok สำหรับผ้าทอ เน้น: ลวดลาย, กระบวนการย้อม, heritage',
  global: 'คุณเป็นผู้เชี่ยวชาญสร้างคอนเทนต์ TikTok สำหรับสินค้าทั่วไป เน้น: ความคุ้มค่า, ฟีเจอร์เด่น, เทรนด์'
};

const category = context.contextCard?.category || 'global';
const systemPrompt = systemPrompts[category] || systemPrompts.global;

// S3: Master Prompt
const masterPrompt = `
【OUTPUT FORMAT】
สร้างคอนเทนต์ TikTok 30 วินาที:
1. Hook (3 วิ): ดึงความสนใจทันที
2. Story (20 วิ): เนื้อหาหลัก
3. CTA (7 วิ): Call to Action

พร้อม Caption + 10 Hashtags

ตอบเป็น JSON เท่านั้น:
{
  "script": {"hook": "...", "story": "...", "cta": "..."},
  "caption": "...",
  "hashtags": ["..."],
  "hook_type": "...",
  "why_it_works": "..."
}
`;

// S1: RCCF Prompt (Role, Context, Constraint, Format)
const userPrompt = `
【สินค้า】${context.contextCard?.product_name}
【หมวดหมู่】${category}
【กลุ่มเป้าหมาย】${context.contextCard?.target_audience}
【Hook ที่ต้องการ】${context.contextCard?.hook_preference}

${masterPrompt}
`;

return {
  systemPrompt,
  userPrompt,
  context: context.contextCard,
  iteration: 1
};

// S6: AI Critic — ให้คะแนนและ feedback
const response = $input.first().json;
const content = JSON.parse(response.content[0].text);

// คำนวณคะแนนตามเกณฑ์
function calculateScore(content) {
  let score = 0;

  // Hook strength (30%)
  const hookLength = content.script?.hook?.length || 0;
  if (hookLength > 20 && hookLength < 100) score += 3;

  // Story flow (25%)
  const storyLength = content.script?.story?.length || 0;
  if (storyLength > 100 && storyLength < 500) score += 2.5;

  // CTA clarity (20%)
  const ctaLength = content.script?.cta?.length || 0;
  if (ctaLength > 20 && ctaLength < 100) score += 2;

  // Hashtags (15%)
  const hashtagCount = content.hashtags?.length || 0;
  if (hashtagCount >= 8) score += 1.5;

  // Format compliance (10%)
  if (content.hook_type && content.why_it_works) score += 1;

  return Math.min(10, score);
}

const criticScore = calculateScore(content);

return {
  content,
  criticScore,
  passed: criticScore >= 7,
  feedback: criticScore >= 7 
    ? 'คอนเทนต์ผ่านมาตรฐาน' 
    : 'ต้องปรับปรุง: ' + (criticScore < 5 ? 'Hook อ่อน' : 'เพิ่ม detail'),
  iteration: $('S1+S3+S5: Prompt Assembly').first().json.iteration
};

// S2: Taste Check — ตรวจสอบกับ reference library
const input = $input.first().json;
const content = input.content;

// ตัวอย่าง taste check (ในจริงจะเทียบกับ reference lib)
const tasteChecks = {
  hasEmoji: /[\u{1F300}-\u{1F9FF}]/u.test(content.caption || ''),
  hashtagCount: (content.hashtags?.length || 0) >= 8,
  hookNotGeneric: !['รู้ไหม', 'เคยเห็น'].some(w => content.script?.hook?.includes(w)),
  ctaHasAction: ['กด', 'follow', 'ลอง', 'ซื้อ', 'สั่ง'].some(w => 
    (content.script?.cta || '').toLowerCase().includes(w)
  )
};

const tasteScore = Object.values(tasteChecks).filter(Boolean).length * 2.5;

return {
  ...input,
  tasteScore,
  tasteChecks
};

// S9: Learning Layer — อธิบาย why it works
const input = $input.first().json;

const learning = {
  hook_type: input.content.hook_type || 'auto',
  why_it_works: input.content.why_it_works || 'Hook นี้ใช้ได้เพราะดึงความสนใจทันที',
  next_try: `ลองใช้ Hook แบบ ${['story', 'process', 'contrast', 'question', 'transformation'].filter(h => h !== input.content.hook_type)[0]} สำหรับสินค้านี้`
};

return {
  content: input.content,
  quality: {
    critic_score: input.criticScore,
    taste_score: input.tasteScore,
    iterations: input.iteration
  },
  learning
};

// Retry loop — เพิ่ม iteration และ retry
const input = $input.first().json;

return {
  ...input,
  iteration: input.iteration + 1,
  retry: true
};
